changeSet.sql:
INSERT INTO jhi_authority (name) VALUES ('ROLE_SUMMARY_PAGE_VIEW') ON CONFLICT (name) DO NOTHING;

DELETE FROM trader_user_authority a
USING trader_user_authority b
WHERE a.authority_name = 'ROLE_POST_AUCTION_PRE_WEIGHING_SUMMARY_VIEW'
  AND b.user_id = a.user_id
  AND b.authority_name = 'ROLE_SUMMARY_PAGE_VIEW';

UPDATE trader_user_authority
SET authority_name = 'ROLE_SUMMARY_PAGE_VIEW'
WHERE authority_name = 'ROLE_POST_AUCTION_PRE_WEIGHING_SUMMARY_VIEW';

DELETE FROM admin_user_authority a
USING admin_user_authority b
WHERE a.authority_name = 'ROLE_POST_AUCTION_PRE_WEIGHING_SUMMARY_VIEW'
  AND b.admin_user_id = a.admin_user_id
  AND b.authority_name = 'ROLE_SUMMARY_PAGE_VIEW';

UPDATE admin_user_authority
SET authority_name = 'ROLE_SUMMARY_PAGE_VIEW'
WHERE authority_name = 'ROLE_POST_AUCTION_PRE_WEIGHING_SUMMARY_VIEW';

DELETE FROM jhi_authority WHERE name = 'ROLE_POST_AUCTION_PRE_WEIGHING_SUMMARY_VIEW';

UPDATE role
SET module_permissions = replace(
    cast(module_permissions as text),
    '"Post-Auction Pre-Weighing Summary"',
    '"SummaryPage"'
)
WHERE module_permissions is not null
  AND cast(module_permissions as text) like '%Post-Auction Pre-Weighing Summary%';
